changeSet.sql:
SELECT setval('clinlims.workflow_page_template_seq',
    COALESCE((SELECT MAX(id) FROM clinlims.workflow_page_template), 0) + 1,
    false);

rollback.sql:
DELETE FROM clinlims.dictionary
WHERE dict_entry = 'MEDLAB'
AND dictionary_category_id = (SELECT id FROM clinlims.dictionary_category WHERE local_abbrev = 'noteBookType');
